import React, { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { Link } from "react-router-dom";
import { getMyB2bOrders } from "../../features/b2b/b2bSlice";
import { getSocket } from "../../socket";
import { paymentMeta } from "./b2bPaymentMeta";
import B2bLayout from "./B2bLayout";
import {
  Package, Clock, CheckCircle2, Truck, XCircle,
  ArrowRight, Search, AlertCircle, FileText, Plus
} from "lucide-react";

const statusConfig = {
  PENDING_APPROVAL: { label: "Pending Approval", color: "bg-amber-50 text-amber-700 border-amber-200", icon: Clock },
  APPROVED: { label: "Approved", color: "bg-indigo-50 text-indigo-700 border-indigo-200", icon: CheckCircle2 },
  PROCESSING: { label: "Processing", color: "bg-violet-50 text-violet-700 border-violet-200", icon: Package },
  SHIPPED: { label: "Shipped", color: "bg-cyan-50 text-cyan-700 border-cyan-200", icon: Truck },
  DELIVERED: { label: "Delivered", color: "bg-emerald-50 text-emerald-700 border-emerald-200", icon: CheckCircle2 },
  CANCELLED: { label: "Cancelled", color: "bg-rose-50 text-rose-700 border-rose-200", icon: XCircle },
  REJECTED: { label: "Rejected", color: "bg-rose-50 text-rose-700 border-rose-200", icon: XCircle },
};

const B2bOrderHistory = () => {
  const dispatch = useDispatch();
  const { orders, isLoading } = useSelector((s) => s.b2b);
  const [statusFilter, setStatusFilter] = useState("");
  const [searchTerm, setSearchTerm] = useState("");

  const fetchOrders = (status) => {
    const params = {};
    if (status) params.procurementStatus = status;
    dispatch(getMyB2bOrders(params));
  };

  useEffect(() => {
    fetchOrders(statusFilter);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [statusFilter]);

  // Real-time B2B order + payment updates
  useEffect(() => {
    const socket = getSocket();
    if (!socket) return;
    const refreshOrders = () => fetchOrders(statusFilter);
    socket.on("b2b:order:created", refreshOrders);
    socket.on("b2b:order:updated", refreshOrders);
    socket.on("b2b:payment:verified", refreshOrders);
    return () => {
      socket.off("b2b:order:created", refreshOrders);
      socket.off("b2b:order:updated", refreshOrders);
      socket.off("b2b:payment:verified", refreshOrders);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [statusFilter]);

  const filtered = (orders || []).filter((o) => {
    if (!searchTerm) return true;
    const lower = searchTerm.toLowerCase();
    return (
      o.orderNumber?.toLowerCase().includes(lower) ||
      o.purchaseOrderNumber?.toLowerCase().includes(lower) ||
      o.txRef?.toLowerCase().includes(lower)
    );
  });

  return (
    <B2bLayout>
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-8">
        <div>
          <h1 className="text-2xl font-black text-slate-900">Procurement Orders</h1>
          <p className="text-sm text-slate-500 font-medium mt-1">
            Track and manage all your wholesale purchase orders
          </p>
        </div>
        <Link
          to="/b2b"
          className="bg-gradient-to-r from-indigo-600 to-violet-600 text-white px-5 py-2.5 rounded-2xl font-bold text-sm hover:shadow-lg hover:shadow-indigo-200 transition-all self-start flex items-center gap-1.5"
        >
          <Plus size={16} /> New Order
        </Link>
      </div>

      {/* Filters */}
      <div className="bg-white rounded-3xl border border-slate-100 p-5 mb-6 shadow-sm flex flex-col sm:flex-row gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
          <input
            type="text"
            placeholder="Search by order, PO or transaction ref..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-10 pr-4 h-10 w-full bg-slate-50 border border-slate-200 rounded-xl text-sm font-medium focus:outline-none focus:ring-2 focus:ring-indigo-500/20"
          />
        </div>
        <select
          value={statusFilter}
          onChange={(e) => setStatusFilter(e.target.value)}
          className="h-10 px-4 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold text-slate-600 focus:outline-none"
        >
          <option value="">All Statuses</option>
          {Object.entries(statusConfig).map(([key, { label }]) => (
            <option key={key} value={key}>{label}</option>
          ))}
        </select>
      </div>

      {/* Orders */}
      {isLoading ? (
        <div className="flex items-center justify-center py-24">
          <div className="w-10 h-10 rounded-full border-2 border-indigo-600 border-t-transparent animate-spin" />
        </div>
      ) : filtered.length > 0 ? (
        <div className="flex flex-col gap-4">
          {filtered.map((order) => {
            const cfg = statusConfig[order.procurementStatus] || statusConfig.PENDING_APPROVAL;
            const StatusIcon = cfg.icon;
            const pay = paymentMeta(order.paymentStatus);
            const total = parseFloat(order.totalPrice || order.totalAmount || 0);
            const date = order.createdAt ? new Date(order.createdAt).toLocaleDateString("en-US", {
              year: "numeric", month: "short", day: "numeric"
            }) : "—";

            return (
              <Link
                key={order.id}
                to={`/b2b/orders/${order.id}`}
                className="bg-white rounded-3xl border border-slate-100 p-6 shadow-sm hover:shadow-md hover:border-indigo-100 transition-all group flex flex-col sm:flex-row sm:items-center gap-5"
              >
                {/* Status badge */}
                <div className="flex items-center gap-4 sm:w-60 flex-shrink-0">
                  <div className={`w-10 h-10 rounded-2xl flex items-center justify-center border ${cfg.color}`}>
                    <StatusIcon size={18} />
                  </div>
                  <div>
                    <span className={`text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded-md border ${cfg.color}`}>
                      {cfg.label}
                    </span>
                    <p className="text-xs text-slate-400 font-medium mt-1">{date}</p>
                  </div>
                </div>

                {/* Order info */}
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-3 mb-1.5 flex-wrap">
                    <span className="font-extrabold text-slate-900 group-hover:text-indigo-600 transition-colors">
                      {order.orderNumber || `ORD-${order.id?.slice(0, 8)}`}
                    </span>
                    <span className={`inline-flex items-center gap-1 text-[9px] font-black uppercase tracking-widest px-2 py-0.5 rounded-md border ${pay.badge}`}>
                      <span className={`w-1 h-1 rounded-full ${pay.dot}`} /> {pay.label}
                    </span>
                    {order.purchaseOrderNumber && (
                      <span className="text-[10px] font-bold text-slate-400 flex items-center gap-1">
                        <FileText size={10} /> PO: {order.purchaseOrderNumber}
                      </span>
                    )}
                  </div>
                  <p className="text-xs text-slate-500 font-medium">
                    {order.itemCount || order.items?.length || "—"} items &bull;{" "}
                    {order.paymentMethod?.replace(/_/g, " ") || "Prepaid"}
                  </p>
                </div>

                {/* Total */}
                <div className="flex items-center gap-4 flex-shrink-0">
                  <div className="text-right">
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Total</span>
                    <span className="text-lg font-black text-slate-950">
                      {total.toLocaleString()}{" "}
                      <span className="text-xs text-slate-400">ETB</span>
                    </span>
                  </div>
                  <ArrowRight size={18} className="text-slate-300 group-hover:text-indigo-500 group-hover:translate-x-0.5 transition-all" />
                </div>
              </Link>
            );
          })}
        </div>
      ) : (
        <div className="flex flex-col items-center justify-center py-24 bg-white rounded-3xl border border-slate-100 shadow-sm">
          <AlertCircle size={48} className="text-slate-200 mb-4" />
          <p className="text-sm font-black text-slate-400 uppercase tracking-widest">
            No orders found
          </p>
        </div>
      )}
    </B2bLayout>
  );
};

export default B2bOrderHistory;
