// Shared payment-status helpers for the B2B UI (new indigo design system).
// Centralized so catalog/checkout/order-list/order-detail all render the
// same badges and use the same "is this order payable?" rule.

export const PAYMENT_STATUS = {
  PAID: {
    label: "Paid",
    badge: "bg-emerald-50 text-emerald-700 border-emerald-100",
    dot: "bg-emerald-500",
  },
  PENDING: {
    label: "Payment Pending",
    badge: "bg-amber-50 text-amber-700 border-amber-100",
    dot: "bg-amber-500",
  },
  UNPAID: {
    label: "Unpaid",
    badge: "bg-rose-50 text-rose-700 border-rose-100",
    dot: "bg-rose-500",
  },
  FAILED: {
    label: "Payment Failed",
    badge: "bg-rose-50 text-rose-700 border-rose-100",
    dot: "bg-rose-500",
  },
  REFUNDED: {
    label: "Refunded",
    badge: "bg-slate-100 text-slate-600 border-slate-200",
    dot: "bg-slate-400",
  },
};

export const paymentMeta = (status) =>
  PAYMENT_STATUS[(status || "UNPAID").toUpperCase()] || PAYMENT_STATUS.UNPAID;

// An order is "payable now" if it isn't already paid, refunded, or cancelled,
// and isn't fully delivered (nothing left to settle online after delivery).
export const isOrderPayable = (order) => {
  if (!order) return false;
  const status = (order.paymentStatus || "UNPAID").toUpperCase();
  if (["PAID", "REFUNDED"].includes(status)) return false;
  if (order.procurementStatus === "CANCELLED") return false;
  return true;
};
